parameters.query:
SELECT COALESCE(
  (
    SELECT risk_id 
    FROM red_flag.risk_definitions
    WHERE risk_name ILIKE '%' || $1 || '%'
    ORDER BY similarity(risk_name, $1) DESC
    LIMIT 1
  ),
  (SELECT risk_id FROM red_flag.risk_definitions ORDER BY risk_id LIMIT 1)
) AS risk_id;

