const item = $input.first();
let parsed;

const raw = item.json.output;
if (typeof raw === 'string') {
  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    const match = raw.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
    if (match) {
      parsed = JSON.parse(match[1]);
    } else {
      throw new Error('Не удалось разобрать ответ агента: ' + raw.slice(0, 300));
    }
  }
} else {
  parsed = raw;
}

const sessionId = $('Select Session ID').first().json.session_id;
const chunkId   = $('Postgres Save Chunks').first().json.chunk_id;

const summaryHtml  = parsed.summary_html  || '<b>Анализ завершён</b>';
const documentType = parsed.document_type || 'Не определён';
const jurisdiction = parsed.jurisdiction  || 'Россия';
const risks        = Array.isArray(parsed.risks) ? parsed.risks : [];

// Нормализация confidence_score: агент может вернуть 0–1 или 0–100
function normalizeScore(raw) {
  const num = typeof raw === 'number' ? raw : parseFloat(raw);
  if (isNaN(num)) return 50; // fallback
  // Если агент вернул 0–1 → конвертируем в 0–100 для INTEGER в БД
  // Если агент вернул 0–100 → оставляем как есть
  const normalized = num > 1 ? num : num * 100;
  return Math.round(Math.min(100, Math.max(0, normalized)));
}

if (risks.length === 0) {
  return [{
    json: {
      session_id:       sessionId,
      chunk_id:         chunkId,
      summary_html:     summaryHtml,
      document_type:    documentType,
      jurisdiction:     jurisdiction,
      risk_name:        null,
      severity:         null,
      confidence_score: null,
      evidence_text:    'Красных флажков не обнаружено',
      recommendation:   null,
      is_empty:         true
    }
  }];
}

const htmlBuffer = Buffer.from(summaryHtml, 'utf-8');
const binaryData = {
  htmlReport: {
    data:     htmlBuffer.toString('base64'),
    mimeType: 'text/html',
    fileName: `report_${sessionId}_${new Date().toISOString()}.html`
  }
};

return risks.map(risk => ({
  json: {
    session_id:       sessionId,
    chunk_id:         chunkId,
    summary_html:     summaryHtml,
    document_type:    documentType,
    jurisdiction:     jurisdiction,
    risk_name:        risk.risk_name        || null,
    severity:         (risk.severity || 'LOW').toUpperCase(),
    confidence_score: normalizeScore(risk.confidence_score),
    evidence_text:    risk.evidence_text    || null,
    recommendation:   risk.recommendation  || null,
    is_empty:         false
  },
  binary: binaryData
}));

// Берём summaryhtml напрямую из ноды, где он был создан
const summaryHtml = $('Code Answer').first().json.summary_html
  || $('Redis Cache Analysis Status').first().json.text
  || '<p>No report generated</p>';

// sessionid берём из ноды, которая его точно имеет
const sessionId = $('Select Session ID').first().json.sessionid;

const htmlBuffer = Buffer.from(summaryHtml, 'utf-8');

return [{
  json: {
    sessionid: sessionId,
    summaryhtml: summaryHtml
  },
  binary: {
    htmlReport: {
      data: htmlBuffer.toString('base64'),
      mimeType: 'text/html',
      fileName: `report_${sessionId}_${new Date().toISOString()}.html`
    }
  }
}];

const crypto = require('crypto');

const accessKey = 'n8n_service';
const secretKey = 'P@ssw0rd_RedFlag_2026!'; 
// Далее нужно заменить на 
// const accessKey = $env.N8N_MINIO_ACCESS_KEY;
// const secretKey = $env.N8N_MINIO_SECRET_KEY;

const region = 'us-east-1';
const host = '84.54.28.193:9000';
const bucket = 'analysis-reports';

const item = $input.first();
const buffer = Buffer.from(item.binary.htmlReport.data, 'base64');
const sessionId = $('Set Merge Analysis Types + Answer').first().json.session_id || 'unknown';

const ts = new Date();
const dateStamp = ts.toISOString().slice(0,10).replace(/-/g,'');
const amzDate = ts.toISOString().replace(/[:\-]/g,'').slice(0,15) + 'Z';
const fileName = `${sessionId}/${dateStamp}_report.html`;

const payloadHash = crypto.createHash('sha256').update(buffer).digest('hex');

const canonicalHeaders = 
  `content-type:text/html\n` +
  `host:${host}\n` +
  `x-amz-content-sha256:${payloadHash}\n` +
  `x-amz-date:${amzDate}\n`;

const signedHeaders = 'content-type;host;x-amz-content-sha256;x-amz-date';

const canonicalRequest = [
  'PUT',
  `/${bucket}/${fileName}`,
  '',
  canonicalHeaders,
  signedHeaders,
  payloadHash
].join('\n');

const credentialScope = `${dateStamp}/${region}/s3/aws4_request`;
const stringToSign = [
  'AWS4-HMAC-SHA256',
  amzDate,
  credentialScope,
  crypto.createHash('sha256').update(canonicalRequest).digest('hex')
].join('\n');

function hmac(key, data, enc) {
  return crypto.createHmac('sha256', key).update(data).digest(enc || undefined);
}

const signingKey = hmac(hmac(hmac(hmac(
  Buffer.from('AWS4' + secretKey), dateStamp), region), 's3'), 'aws4_request');
const signature = hmac(signingKey, stringToSign, 'hex');

const authHeader = `AWS4-HMAC-SHA256 Credential=${accessKey}/${credentialScope}, SignedHeaders=${signedHeaders}, Signature=${signature}`;

return [{
  json: {
    uploadUrl: `http://${host}/${bucket}/${fileName}`,
    authHeader,
    amzDate,
    payloadHash,
    fileName
  },
  binary: item.binary
}];

const rawHtml = $('Prepare Report Binary').first().json.summaryhtml ?? '';

const cleanHtml = rawHtml
  // Заголовки → жирный + двойной перенос
  .replace(/<h[1-6][^>]*>(.*?)<\/h[1-6]>/gi, '\n\n<b>$1</b>\n')
  // Пункты списка → тире + перенос
  .replace(/<li[^>]*>(.*?)<\/li>/gi, '\n• $1')
  // Абзацы → двойной перенос
  .replace(/<\/p>/gi, '\n\n')
  .replace(/<p[^>]*>/gi, '')
  // <br> → перенос
  .replace(/<br\s*\/?>/gi, '\n')
  // Убрать теги ul/ol/div/span и прочие неподдерживаемые
  .replace(/<\/?(?!b>|\/b>|i>|\/i>|u>|\/u>|s>|\/s>|code>|\/code>|pre>|\/pre>|a[ >]|\/a>)[a-z][^>]*>/gi, '')
  // Убрать тройные и более переносы
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const fileName = $('Build S3 Signature').first().json.fileName;
const sessionId = $('Select Session ID').first().json.session_id;

return [{
  json: {
    session_id: sessionId,
    s3_status: 'SUCCESS',
    s3_message: `\n\n✅ Отчёт <code>${fileName}</code> сохранён в analysis-reports`,
    file_name: fileName,
    clean_html: cleanHtml
  }
}];

const telegramId = $('Extract Message Fields').first().json.telegramid;
const dailyUsed = $('Redis Increment Daily Counter').first().json.value ?? 1;
const dailyLimit = 3; // Free тариф
const remaining = Math.max(0, dailyLimit - dailyUsed);

const emoji = remaining === 0 ? '🔴' : remaining === 1 ? '🟡' : '🟢';

return [{
  json: {
    chat_id: $('Extract Message Fields').first().json.chatid,
    used: dailyUsed,
    remaining: remaining,
    status_text: `${emoji} Использовано запросов сегодня: ${dailyUsed} из ${dailyLimit}\nОсталось: ${remaining}\n\nЧто делаем дальше?`
  }
}];
